import asyncio, json, base64, websockets

URL = "wss://api.openai.com/v1/realtime?model=gpt-4o-realtime-preview-2024-10-01"
HEADERS = {
    "Authorization": "Bearer <OPENAI_API_KEY>",
    "OpenAI-Beta": "realtime=v1",
}

async def realtime_session(mic_stream):
    """mic_stream: async generator yielding raw PCM int16 bytes at 24 kHz mono."""
    async with websockets.connect(URL, additional_headers=HEADERS) as ws:
        # Configure the session
        await ws.send(json.dumps({
            "type": "session.update",
            "session": {
                "modalities": ["audio", "text"],
                "input_audio_format": "pcm16",
                "output_audio_format": "pcm16",
                "voice": "alloy",
                "turn_detection": {
                    "type": "server_vad",
                    "threshold": 0.5,
                    "silence_duration_ms": 500,
                },
            }
        }))

        async def send_audio():
            async for chunk in mic_stream:
                await ws.send(json.dumps({
                    "type": "input_audio_buffer.append",
                    "audio": base64.b64encode(chunk).decode(),
                }))

        async def receive_events(speaker_queue: asyncio.Queue):
            async for msg in ws:
                event = json.loads(msg)
                etype = event["type"]
                if etype == "response.audio.delta":
                    pcm = base64.b64decode(event["delta"])
                    await speaker_queue.put(pcm)
                elif etype == "response.audio_transcript.delta":
                    print(event["delta"], end="", flush=True)
                elif etype == "input_audio_buffer.speech_started":
                    # User started speaking — cancel playback
                    while not speaker_queue.empty():
                        speaker_queue.get_nowait()
                elif etype == "response.cancelled":
                    print("\n[response cancelled — user interrupted]")

        speaker_queue: asyncio.Queue = asyncio.Queue()
        await asyncio.gather(send_audio(), receive_events(speaker_queue))

import asyncio

class VoiceAgent:
    def __init__(self, pipeline_fn):
        self.pipeline_fn = pipeline_fn
        self.audio_queue: asyncio.Queue = asyncio.Queue()
        self._task: asyncio.Task | None = None

    def on_speech_started(self):
        """VAD detected user speaking — cancel current response immediately."""
        if self._task and not self._task.done():
            self._task.cancel()
        # Flush any queued audio chunks so the speaker goes silent fast
        while not self.audio_queue.empty():
            self.audio_queue.get_nowait()

    def on_utterance_final(self, transcript: str):
        """ASR emitted a complete utterance — start generating a response."""
        if not transcript.strip():
            return

        async def run():
            try:
                await self.pipeline_fn(transcript, self.audio_queue)
            except asyncio.CancelledError:
                pass  # user interrupted — clean exit

        self._task = asyncio.ensure_future(run())
